PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:fixtureType ?cg . ?child a :Fixtures ; p:fixtureType ?cg . ?l p:technicianID ?pg . ?parent a :Lighting_Technicians ; p:technicianID ?pg . } GROUP BY ?child }
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Lighting_Technicians } }
  FILTER(?nf = ?total)
}

PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name ?description WHERE {
  ?lighting_technicians_fixtures a :Lighting_Technicians_Fixtures .
  ?fixtures a :Fixtures .
  ?lighting_technicians_fixtures p:hasFixtures ?fixtures .
  ?lighting_technicians a :Lighting_Technicians .
  ?lighting_technicians_fixtures p:hasLighting_Technicians ?lighting_technicians .
  OPTIONAL { ?lighting_technicians p:name ?name . }
  OPTIONAL { ?fixtures p:description ?description . }
}
